  const setStatus = (id, idx) => setFeed((f) => f.map((p) => { if (p.id !== id) return p; const np = { ...p, status: idx }; if (idx === 4 && !p.fulfilled) { np.fulfilled = "Just now"; np.days = p.days || 2; np.winner = p.winner || "anon"; } return np; }));
