  const applyDirect = (p) => { setFeed((f) => f.map((x) => x.id === p.id ? { ...x, status: Math.max(x.status, 1), applicants: (x.applicants || 0) + 1 } : x)); onToast?.("Application sent directly to the hiring manager · no agency fee"); };
